// Loose category guess used only for the picker filter chips.
function guessCategory(id, name) {
    const n = name.toLowerCase();
    if (/police|cop|gun|weapon|ammu|swat|enemy|target|crosshair|wanted|arms|tank|gang|deathmatch/.test(n)) return 'Emergency & Combat';
    if (/hospital|medic|ambulance|health|safehouse/.test(n)) return 'Services';
    if (/car|truck|heli|plane|boat|bike|jet|vehicle|garage|taxi|bus|train|tow|cable/.test(n)) return 'Vehicles';
    if (/shop|store|cash|dollar|money|bank|sale|cloth|barber|tattoo|mask|gun shop/.test(n)) return 'Shops & Money';
    if (/race|golf|tennis|darts|activity|sport|gym|strength|stunt|jump|yoga/.test(n)) return 'Activities';
    return 'General';
}

const BLIP_DATA = AVAILABLE_IDS.map(function (id) {
    const name = BLIP_NAMES[id] || ('Blip #' + id);
    return { id: id, name: name, cat: guessCategory(id, name) };
});
